local function renameComponents(window, windowId)
    window:Rename(window:GetName() .. "-" .. tostring(windowId))
    local count = window:GetChildCount()
    if count == 0 then
        return
    end
    for index = 1, count do
        renameComponents(window:GetChildByIndex(index - 1), windowId)
    end
end

IGUIWindow = class("IGUIWindow", EventObservable) ---@class IGUIWindow  : EventObservable

function IGUIWindow:ctor(name, ...)
    self.root = GUIManager:loadWindowFromJSON(name, true)
    if not self.root then
        HostApi.log(string.format("Can't find window json [%s]", name), 1)
        return
    end
    self.windowId = GUIManager:applyWindowId()
    renameComponents(self.root, self.windowId)
    self.__name = name
    self:onLoad(...)
    MemoryPool.pushTable(self)
end

